/* xerox — zine overrides */

/* ── Page background ── */
body{background-color:var(--wp--preset--color--base)!important;color:var(--wp--preset--color--contrast);}

/* ── Zero radius everywhere ── */
*,*::before,*::after{border-radius:0!important;}

/* ── Navigation: all-caps + double-slash separators ── */
.wp-block-navigation .wp-block-navigation-item__content{text-transform:uppercase;letter-spacing:0.12em;font-family:var(--wp--preset--font-family--sans);font-weight:700;}
.wp-block-navigation .wp-block-navigation-item + .wp-block-navigation-item > .wp-block-navigation-item__content::before{content:'// ';color:var(--wp--preset--color--muted);}

/* ── Site title: bold stamp ── */
.wp-block-site-title a{font-family:var(--wp--preset--font-family--display);font-weight:700;text-transform:uppercase;letter-spacing:0.06em;color:var(--wp--preset--color--contrast);text-decoration:none;}

/* ── Headings: ransom-note density ── */
h1,h2,h3,.wp-block-heading{font-family:var(--wp--preset--font-family--display);font-weight:700;text-transform:uppercase;letter-spacing:0.02em;line-height:0.95;}

/* ── Compact section spacing ── */
.wp-block-group,.wp-block-cover,.wp-block-columns{row-gap:clamp(16px,2vw,24px)!important;}
.wp-block-group + .wp-block-group{margin-top:clamp(16px,2vw,24px)!important;}

/* ── Section dividers ── */
hr,.wp-block-separator{border:none;border-top:1px solid var(--wp--preset--color--subtle);margin-block:clamp(16px,2vw,24px);width:100%;}

/* ── Buttons: border-only ink stamp ── */
.wp-block-button__link,
.wc-block-components-button,
.button,
input[type='submit'],
button:not(.wp-block-navigation__responsive-container-open):not(.wp-block-navigation__responsive-container-close){
  background:transparent!important;
  color:var(--wp--preset--color--contrast)!important;
  border:2px solid var(--wp--preset--color--contrast)!important;
  border-radius:0!important;
  box-shadow:none!important;
  font-family:var(--wp--preset--font-family--display);
  font-weight:700;
  text-transform:uppercase;
  letter-spacing:0.1em;
  padding:0.45em 1.1em;
  transition:background 120ms ease,color 120ms ease;
}
.wp-block-button__link:hover,
.wc-block-components-button:hover,
.button:hover,
input[type='submit']:hover{
  background:var(--wp--preset--color--contrast)!important;
  color:var(--wp--preset--color--base)!important;
}
/* CTA accent variant */
.wp-block-button.is-style-outline .wp-block-button__link,
.wp-block-button.is-style-accent .wp-block-button__link{
  border-color:var(--wp--preset--color--accent)!important;
  color:var(--wp--preset--color--accent)!important;
}
.wp-block-button.is-style-outline .wp-block-button__link:hover,
.wp-block-button.is-style-accent .wp-block-button__link:hover{
  background:var(--wp--preset--color--accent)!important;
  color:var(--wp--preset--color--base)!important;
}

/* ── Product cards: Polaroid style ── */
.wc-block-grid__product,
.wp-block-woocommerce-product-template > li,
ul.products li.product{
  background:var(--wp--preset--color--surface)!important;
  border:2px solid var(--wp--preset--color--contrast)!important;
  box-shadow:none!important;
  padding:8px 8px 48px 8px!important;
  margin:0!important;
  gap:0!important;
}
.wc-block-grid__product-image img,
ul.products li.product a img{
  display:block;
  width:100%;
  aspect-ratio:1/1;
  object-fit:cover;
  filter:grayscale(30%) contrast(1.15);
  border:0;
}
.wc-block-grid__product-title,
ul.products li.product .woocommerce-loop-product__title{
  font-family:var(--wp--preset--font-family--display);
  font-weight:700;
  text-transform:uppercase;
  font-size:var(--wp--preset--font-size--xs);
  letter-spacing:0.08em;
  margin-top:10px;
  color:var(--wp--preset--color--contrast);
}
.wc-block-grid__product-price,
ul.products li.product .price{
  font-family:var(--wp--preset--font-family--display);
  font-size:var(--wp--preset--font-size--xs);
  color:var(--wp--preset--color--contrast);
}
.wc-block-grid__products,
ul.products{
  gap:16px!important;
  grid-gap:16px!important;
}

/* ── Sale badge: accent stamp ── */
.wc-block-grid__product-onsale,
ul.products li.product .onsale{
  background:var(--wp--preset--color--accent)!important;
  color:var(--wp--preset--color--base)!important;
  border:none!important;
  border-radius:0!important;
  font-family:var(--wp--preset--font-family--display);
  font-weight:700;
  text-transform:uppercase;
  letter-spacing:0.1em;
  font-size:var(--wp--preset--font-size--2-xs);
  padding:2px 6px;
  box-shadow:none!important;
}

/* ── WooCommerce account / table overrides (zine voice) ── */
.woocommerce-orders-table th,.woocommerce-table--order-details thead th{
  background:var(--wp--preset--color--subtle);
  text-transform:uppercase;
  letter-spacing:0.1em;
  font-weight:700;
  border-radius:0;
}
.woocommerce-orders-table .button,
.woocommerce-MyAccount-content .button{
  background:transparent;
  color:var(--wp--preset--color--contrast);
  border:2px solid var(--wp--preset--color--contrast);
  border-radius:0;
  font-family:var(--wp--preset--font-family--display);
  font-weight:700;
  text-transform:uppercase;
  letter-spacing:0.1em;
  box-shadow:none;
}
.woocommerce-orders-table .button:hover,
.woocommerce-MyAccount-content .button:hover{
  background:var(--wp--preset--color--contrast);
  color:var(--wp--preset--color--base);
  border-color:var(--wp--preset--color--contrast);
}
.woocommerce-EditAccountForm input,
.woocommerce-address-fields__field-wrapper input,
.woocommerce-EditAccountForm select,
.woocommerce-address-fields__field-wrapper select{
  border-radius:0;
  border:2px solid var(--wp--preset--color--border);
  background:var(--wp--preset--color--surface);
}

/* ── Footer: typewriter ticker feel ── */
.wp-block-template-part[class*='footer'] .wp-block-paragraph,
footer .wp-block-paragraph{
  font-family:var(--wp--preset--font-family--display);
  font-size:var(--wp--preset--font-size--xs);
  text-transform:uppercase;
  letter-spacing:0.12em;
  color:var(--wp--preset--color--muted);
}

/* ── Inherited site-title mobile guard ── */
.wp-block-site-title,.wp-block-site-title a{max-width:100%;min-width:0;overflow-wrap:anywhere;word-break:normal;}
.wp-block-group:has(>.wp-block-site-title){max-width:100%;min-width:0;}

/* ── Nav tap targets (a11y) ── */
.wp-block-navigation__responsive-container-open,
.wp-block-navigation__responsive-container-close{min-width:44px;min-height:44px;display:inline-flex;align-items:center;justify-content:center;padding:0;}
.wp-block-navigation .wp-block-navigation-item__content{min-height:32px;display:inline-flex;align-items:center;padding-inline:var(--wp--preset--spacing--2-xs);}

/* ── Cart disabled item contrast (a11y) ── */
.wc-block-cart-item.is-disabled .wc-block-components-product-name,
.is-disabled>.wc-block-cart-item__product .wc-block-components-product-name{color:var(--wp--preset--color--contrast);opacity:1;}

/* ── Product reviews overflow guard ── */
.wp-block-woocommerce-product-reviews{max-width:100%;min-width:0;box-sizing:border-box;}
.wp-block-woocommerce-product-reviews-title,#reviews,.wp-block-woocommerce-product-review-form .comment-reply-title{max-width:100%;overflow-wrap:anywhere;word-break:normal;white-space:normal;}
